import { computed, linkedSignal, resource, signal, } from '@angular/core';
import { UniBaseDatasource } from './base-datasource';
export class UniServerSideDatasource extends UniBaseDatasource {
    constructor(dataLoader, initialPageSize = 10) {
        super();
        this.dataLoader = dataLoader;
        this._pageNumber = signal(1);
        this._pageSize = signal(10);
        this._sortColumn = signal(undefined);
        this._sortDirection = signal('indet');
        this.filter = signal({});
        this.sortColumn = computed(() => this._sortColumn());
        this.sortDirection = computed(() => this._sortDirection());
        this.totalRecords = signal(0);
        this.pageIndex = computed(() => this._pageNumber() - 1);
        this.pageSize = computed(() => this._pageSize());
        this.pageCount = computed(() => {
            const total = this.totalRecords();
            const size = this.pageSize();
            return total > 0 ? Math.ceil(total / size) : 0;
        });
        this._records = linkedSignal({
            source: () => ({
                val: this.dataResource.value(),
                status: this.dataResource.status(),
            }),
            computation: (source, previous) => {
                if (source.status === 'loading' && previous) {
                    return previous.value;
                }
                return source.val?.data ?? [];
            },
        });
        this.records = this._records.asReadonly();
        this.recordCount = computed(() => this.totalRecords());
        this.isLoading = computed(() => this.dataResource.isLoading());
        this.error = computed(() => this.dataResource.error());
        this.hasError = computed(() => this.dataResource.hasValue() === false && this.error() !== undefined);
        this._pageSize.set(initialPageSize);
        this.dataResource = resource({
            params: () => ({
                pageNumber: this._pageNumber(),
                pageSize: this._pageSize(),
                sortColumn: this._sortColumn(),
                sortDirection: this._sortDirection(),
                filter: this.filter(),
            }),
            loader: async (params) => {
                const request = params.params;
                const response = await this.dataLoader(request);
                if (request.pageNumber === 1 || this.totalRecords() === 0) {
                    this.totalRecords.set(response.totalRecords);
                }
                return response;
            },
        });
    }
    sortRecords(sort) {
        this.sort.set(sort);
        this._sortColumn.set(sort.column);
        this._sortDirection.set(sort.direction);
        this._pageNumber.set(1);
    }
    firstPage() {
        this._pageNumber.set(1);
    }
    nextPage() {
        if (this._pageNumber() < this.pageCount()) {
            this._pageNumber.update((n) => n + 1);
        }
    }
    previousPage() {
        if (this._pageNumber() > 1) {
            this._pageNumber.update((n) => n - 1);
        }
    }
    lastPage() {
        this._pageNumber.set(this.pageCount());
    }
    jumpToPage(page) {
        if (page >= 1 && page <= this.pageCount()) {
            this._pageNumber.set(page);
        }
    }
    setPageSize(size) {
        if (size > 0) {
            this._pageSize.set(size);
            this._pageNumber.set(1);
        }
    }
    setFilter(filterValues) {
        this.filter.set(filterValues);
        this._pageNumber.set(1);
    }
    clearFilter() {
        this.filter.set({});
        this._pageNumber.set(1);
    }
    refresh() {
        this.dataResource.reload();
    }
    getPageRequest() {
        return {
            pageNumber: this._pageNumber(),
            pageSize: this._pageSize(),
            sortColumn: this._sortColumn(),
            sortDirection: this._sortDirection(),
            filter: this.filter(),
        };
    }
}
